export default function myInstanceOf(obj, Constructor) {
  if (typeof Constructor !== 'function') {
    throw new TypeError('myInstanceOf: Constructor must be a function');
  }

  const targetProto = Constructor.prototype;
  if (targetProto === null || (typeof targetProto !== 'object' && typeof targetProto !== 'function')) {
    throw new TypeError('myInstanceOf: Constructor must have an object prototype');
  }

  if (obj === null || obj === undefined) return false;

  const t = typeof obj;
  if (t !== 'object' && t !== 'function') return false;

  let current = Object.getPrototypeOf(obj);
  while (current !== null) {
    if (current === targetProto) return true;
    current = Object.getPrototypeOf(current);
  }

  return false;
}
